// İnterfeysləri icra etmə sintaksisi
interface Vehicle {
  brand: string;
  drive(): string;
}

class Car implements Vehicle {
  brand: string;

  constructor(brand: string) {
    this.brand = brand;
  }

  drive(): string {
    return `${this.brand} is driving`;
  }
}

let car = new Car('Toyota');
console.log(car.drive()); // Toyota is driving
// class InvalidCar implements Vehicle { } // Xəta: brand və drive təmin edilməyib

// İnterfeyslər vs Tip aliasları
type Id = number | string;

interface User {
  id: Id;
  name: string;
}

class UserProfile implements User {
  id: Id;
  name: string;

  constructor(id: Id, name: string) {
    this.id = id;
    this.name = name;
  }
}

let user = new UserProfile(1, 'Ali');
console.log(user); // UserProfile { id: 1, name: 'Ali' }
// class InvalidUser implements User { name: 'Vəli'; } // Xəta: id təmin edilməyib

// Çoxlu interfeys icrası
interface Printable {
  print(): string;
}

interface Loggable {
  log(): string;
}

class Document implements Printable, Loggable {
  title: string;

  constructor(title: string) {
    this.title = title;
  }

  print(): string {
    return `Printing ${this.title}`;
  }

  log(): string {
    return `Logging ${this.title}`;
  }
}

let doc = new Document('Report');
console.log(doc.print()); // Printing Report
console.log(doc.log()); // Logging Report
// class InvalidDoc implements Printable, Loggable { } // Xəta: print və log təmin edilməyib

