// Təhlükəsizlik nümunəsi
interface User {
  name: string;
  getRole(): string;
}

class Admin implements User {
  name: string;

  constructor(name: string) {
    this.name = name;
  }

  getRole(): string {
    return 'admin';
  }
}

function getUserInfo(user: User): string {
  return `${user.name} has role ${user.getRole()}`;
}

let admin = new Admin('Ali');
