// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
  getPrice(): number;
}

interface Discountable {
  applyDiscount(discount: number): number;
}

class Smartphone implements Product, Discountable {
  id: number;
  name: string;
  price: number;

  constructor(id: number, name: string, price: number) {
    this.id = id;
    this.name = name;
    this.price = price;
  }

  getPrice(): number {
    return this.price;
  }

  applyDiscount(discount: number): number {
    return this.price * (1 - discount);
  }
}

let phone = new Smartphone(1, 'Smartphone', 1000);
console.log(phone.getPrice()); // 1000
console.log(phone.applyDiscount(0.1)); // 900

